#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;

my $next = $cgi->param('next') || '/';

my $redirect_url = $next;

if ($redirect_url !~ m{^https?://}) {
    if ($redirect_url !~ m{^/}) {
        $redirect_url = '/' . $redirect_url;
